plugin.detectCode:
const t = input.trim();
const hasSection = /^\[[\w.]+\]$/m.test(t);
const hasKV = /^\w[\w.-]*\s*=\s*.+$/m.test(t);
return (hasKV && hasSection) ? 0.9 : hasKV ? 0.4 : 0;

plugin.executeCode:
const lines = input.split('\n');
const sections = [{ name: '(root)', entries: [] }];
let current = sections[0];

for (const rawLine of lines) {
  const line = rawLine.trim();
  if (!line || line.startsWith('#')) continue;
  const secMatch = line.match(/^\[([^\]]+)\]$/);
  if (secMatch) {
    current = { name: secMatch[1], entries: [] };
    sections.push(current);
    continue;
  }
  const eqIdx = line.indexOf('=');
  if (eqIdx > 0) {
    const key = line.slice(0, eqIdx).trim();
    const val = line.slice(eqIdx + 1).trim();
    current.entries.push({ key, val });
  }
}

const out = [];
for (const sec of sections) {
  if (sec.entries.length === 0) continue;
  out.push(`[${sec.name}]`);
  const maxKey = Math.max(...sec.entries.map(e => e.key.length));
  for (const { key, val } of sec.entries) {
    out.push(`  ${key.padEnd(maxKey)}  =  ${val}`);
  }
  out.push('');
}
if (out.length === 0) return { output: 'No TOML key-value pairs found.', outputLanguage: 'text' };
return { output: out.join('\n').trimEnd(), outputLanguage: 'text' };
